mapper.select:
SELECT t.*, COALESCE(c.warning_threshold, 0) AS warningThreshold
FROM coins_cross_exchange_arbitrage_task t
LEFT JOIN coins_arbitrage_warning_config c ON t.id = c.task_id

    AND t.status = 1

        AND c.arbitrage_type = #{arbitrageType}


        AND c.status = #{status}


        AND c.liquidation_config_status = #{liquidationConfigStatus}
